import React, { useState, useEffect } from 'react';
import axios from 'axios';

function ClientDashboard() {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const fetchAllProjects = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setProjects(res.data);
      setLoading(false);
    } catch (err) {
      setError("❌ डेटा लोड करता आला नाही. सर्व्हर चालू असल्याची खात्री करा.");
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAllProjects();
  }, []);

  // क्लायंटकडून बदल (Revisions) पाठवण्यासाठी फंक्शन
  const handleRevisionRequest = async (id) => {
    const revisionMsg = document.getElementById(`rev-${id}`).value;
    if (!revisionMsg.trim()) return alert("कृपया काय बदल हवे आहेत ते लिहा!");

    try {
      await axios.put(`http://localhost:5000/api/update-status/${id}`, {
        revisionsRequested: revisionMsg
      });
      alert("✅ तुमची विनंती पाठवली गेली आहे!");
      document.getElementById(`rev-${id}`).value = ""; // इनपुट क्लिअर करा
      fetchAllProjects(); // रिफ्रेश करा
    } catch (err) {
      alert("❌ विनंती पाठवता आली नाही.");
    }
  };

  return (
    <div className="container-fluid py-5 mt-4 px-lg-5">
      <div className="text-center mb-5">
        <h2 className="fw-bold text-primary">Live Project Tracker</h2>
        <p className="text-muted">येथे आमच्या चालू असलेल्या सर्व प्रोजेक्ट्सचा रिअल-टाइम रिपोर्ट दिसेल.</p>
      </div>

      {loading ? (
        <div className="text-center py-5">
          <div className="spinner-border text-primary" role="status"></div>
          <p className="mt-2">प्रोजेक्ट्स लोड होत आहेत...</p>
        </div>
      ) : error ? (
        <div className="alert alert-danger text-center shadow-sm">{error}</div>
      ) : (
        <div className="row g-4">
          {projects.length > 0 ? projects.map((proj) => (
            <div className="col-12 mb-4" key={proj._id}>
              <div className="card shadow-lg border-0 rounded-4 overflow-hidden">
                {/* कार्ड हेडर */}
                <div className="card-header bg-dark text-white p-3 d-flex justify-content-between align-items-center">
                  <h5 className="mb-0 fw-bold">{proj.fullName} - <small className="text-warning">{proj.serviceType}</small></h5>
                  <span className={`badge ${proj.status === 'Completed' ? 'bg-success' : 'bg-warning text-dark'}`}>
                    {proj.status}
                  </span>
                </div>

                <div className="card-body p-4 bg-white">
                  <div className="row align-items-center">
                    {/* १. प्रोग्रेस सेक्शन */}
                    <div className="col-md-4 mb-3 mb-md-0">
                      <label className="fw-bold small mb-1">Work Progress</label>
                      <div className="d-flex align-items-center gap-2">
                        <div className="progress flex-grow-1" style={{ height: '12px' }}>
                          <div 
                            className={`progress-bar progress-bar-striped progress-bar-animated ${proj.progress === 100 ? 'bg-success' : 'bg-primary'}`} 
                            style={{ width: `${proj.progress}%` }}
                          ></div>
                        </div>
                        <span className="fw-bold text-primary">{proj.progress}%</span>
                      </div>
                    </div>

                    {/* २. पेमेंट समरी सेक्शन (नवीन) */}
                    <div className="col-md-4 mb-3 mb-md-0 border-start border-end px-4">
                      <div className="d-flex justify-content-between mb-1">
                        <span className="small text-muted">Total Budget:</span>
                        <span className="fw-bold text-dark">₹{proj.totalBudget}</span>
                      </div>
                      <div className="d-flex justify-content-between mb-1">
                        <span className="small text-muted">Advance Paid:</span>
                        <span className="fw-bold text-success">₹{proj.advancePaid}</span>
                      </div>
                      <hr className="my-1" />
                      <div className="d-flex justify-content-between">
                        <span className="small fw-bold">Remaining:</span>
                        <span className="fw-bold text-danger">₹{proj.totalBudget - proj.advancePaid}</span>
                      </div>
                    </div>

                    {/* ३. बदल सुचवण्याचा सेक्शन (नवीन) */}
                    <div className="col-md-4">
                      <label className="fw-bold small mb-1 text-primary">Need Changes / Revisions?</label>
                      <div className="input-group">
                        <input 
                          type="text" id={`rev-${proj._id}`} 
                          className="form-control form-control-sm" 
                          placeholder="तुमचे बदल इथे लिहा..." 
                        />
                        <button 
                          className="btn btn-primary btn-sm fw-bold" 
                          onClick={() => handleRevisionRequest(proj._id)}
                        >
                          Send
                        </button>
                      </div>
                      {proj.revisionsRequested && (
                        <p className="mt-1 x-small text-muted" style={{fontSize: '11px'}}>
                          <strong>Current Request:</strong> {proj.revisionsRequested}
                        </p>
                      )}
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )) : (
            <div className="text-center py-5 text-muted">अद्याप कोणतेही प्रोजेक्ट्स उपलब्ध नाहीत.</div>
          )}
        </div>
      )}

      <div className="mt-5 text-center small text-muted">
        <i className="fas fa-info-circle me-1"></i> हा डेटा रिअल-टाइममध्ये एडमिनकडून अपडेट केला जातो.
      </div>
    </div>
  );
}

export default ClientDashboard;
